<?php declare(strict_types=1);session_start();require __DIR__.'/../includes/functions.php';require __DIR__.'/autoload.php';use App\Students\Student;$_SESSION['students']??=[];$message='';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$action=(string)($_POST['action']??'add');if($action==='reset'){$_SESSION['students']=[];header('Location:index.php');exit;}try{$name=trim((string)($_POST['name']??''));$age=filter_input(INPUT_POST,'age',FILTER_VALIDATE_INT);$id=trim((string)($_POST['studentID']??''));if($name===''||$age===false||$age===null)throw new InvalidArgumentException('Thông tin sinh viên không hợp lệ.');foreach($_SESSION['students'] as $s)if(strcasecmp($s['studentID'],$id)===0)throw new RuntimeException('Mã sinh viên đã tồn tại.');$student=new Student($name,$age,$id);$_SESSION['students'][]=$student->data();$message='Đã thêm sinh viên.';}catch(Throwable $e){$error=$e->getMessage();}}$pageTitle='Bài 08 - Students';$basePath='..';$current='bai08';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 08</div><h1>Quản lý sinh viên</h1><p class="subtitle">Student kế thừa Person, dùng namespace App\Students và autoloading.</p><?php if($message):?><div class="alert ok"><?=e($message)?></div><?php endif;?><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><section class="card"><h2>Thêm sinh viên</h2><form method="post"><div class="form-grid"><div class="group"><label>Họ tên</label><input name="name" value="<?=old('name','Nguyễn Hữu Thắng')?>" required></div><div class="group"><label>Tuổi</label><input type="number" name="age" min="1" max="120" value="<?=old('age','21')?>" required></div><div class="group full"><label>Mã sinh viên</label><input name="studentID" value="<?=old('studentID','2001234567')?>" required></div></div><div class="actions"><button class="btn primary" name="action" value="add">Thêm sinh viên</button><button class="btn danger" name="action" value="reset">Xóa danh sách</button></div></form></section><section class="card" style="margin-top:20px"><h2>Danh sách sinh viên</h2><?php if($_SESSION['students']):?><div class="table-wrap"><table><thead><tr><th>Mã sinh viên</th><th>Họ tên</th><th>Tuổi</th></tr></thead><tbody><?php foreach($_SESSION['students'] as $s):?><tr><td><?=e($s['studentID'])?></td><td><?=e($s['name'])?></td><td><?=e((string)$s['age'])?></td></tr><?php endforeach;?></tbody></table></div><?php else:?><p class="muted">Chưa có sinh viên.</p><?php endif;?></section><?php require __DIR__.'/../includes/footer.php';?>
